#include <stdio.h>
#include <string.h>

#define MAX 100

char stack[MAX];
int top = -1;

void push(char c) {
    stack[++top] = c;
}

char pop() {
    return stack[top--];
}

int main() {
    char postfix[MAX];
    printf("Enter a postfix expression: ");
    scanf("%s", postfix);
    int n = strlen(postfix);
    for (int i = 0; i < n; i++) {
        if (postfix[i] >= 'a' && postfix[i] <= 'z') {
            push(postfix[i]);
        } else {
            char op2 = pop();
            char op1 = pop();
            printf("%c%c%c", postfix[i], op1, op2);
        }
    }
    return 0;
}

